css:
:host { display: block; }
.pricing { padding: 4rem 2rem; text-align: center; }
h2 { font-size: 2rem; color: white; margin: 0 0 3rem; }
.grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(280px, 1fr)); gap: 1.5rem; max-width: 1000px; margin: 0 auto; }
.card { background: #1f1f23; border: 1px solid #2a2a2e; border-radius: 12px; padding: 2rem; position: relative; }
.card.featured { border-color: var(--primary); }
.badge { position: absolute; top: -12px; left: 50%; transform: translateX(-50%); background: var(--primary); color: #111; font-size: 0.75rem; font-weight: 700; padding: 0.25rem 1rem; border-radius: 20px; }
h3 { font-size: 1.25rem; color: white; margin: 0 0 0.5rem; }
.price { font-size: 2.5rem; font-weight: 800; color: white; margin: 0.5rem 0 1.5rem; }
.price span { font-size: 1rem; font-weight: 400; color: #8b8b90; }
ul { list-style: none; padding: 0; margin: 0 0 2rem; }
li { padding: 0.5rem 0; color: #adadb0; border-bottom: 1px solid #2a2a2e; font-size: 0.9rem; }
li:last-child { border: none; }
.btn { display: block; padding: 0.75rem; background: #2a2a2e; color: white; border-radius: 8px; text-decoration: none; font-weight: 600; transition: background 0.2s; }
.btn:hover { background: #3a3a3e; }
.btn-primary { background: var(--primary); color: #111; }
.btn-primary:hover { opacity: 0.9; }
